<h2>Behälter</h2><table><tr><th>Code</th><th>Name</th><th>Typ</th><th>Ort</th><th>Notizen</th><th>Artikel</th></tr><?php foreach($containers as $c):?><tr><td><?=h($c['code'])?></td><td><?=h($c['name'])?></td><td><?=h($c['type'])?></td><td><?=h($c['location_code'].' '.$c['location_name'])?></td><td><?=h($c['notes'])?></td><td><?=h($c['item_count'])?></td></tr><?php endforeach?></table><h3>Behälter anlegen/bearbeiten</h3><form method="post" action="?p=save_container" class="form small"><?=csrf_field()?><input name="id" placeholder="ID für Update optional"><input required name="code" placeholder="Code"><input required name="name" placeholder="Name"><input name="type" placeholder="Typ"><select required name="location_id"><?php foreach($locations as $l):?><option value="<?=h($l['id'])?>"><?=h($l['code'].' '.$l['name'])?></option><?php endforeach?></select><textarea name="notes" placeholder="Notizen"></textarea><button>Speichern</button></form>
